#include <stdio.h>

typedef struct {
    long long num1;
    long long num2;
} Calculator;

long long add(Calculator *c) { return c->num1 + c->num2; }
long long subtract(Calculator *c) { return c->num1 - c->num2; }
long long multiply(Calculator *c) { return c->num1 * c->num2; }
double divide(Calculator *c) { return (double)c->num1 / (double)c->num2; }

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        Calculator calc;
        scanf("%lld %lld", &calc.num1, &calc.num2);
        printf("%lld\n", add(&calc));
        printf("%lld\n", subtract(&calc));
        printf("%lld\n", multiply(&calc));
        printf("%g\n", divide(&calc));
    }
    return 0;
}

