#include <bits/stdc++.h>
using namespace std;

class Calculator {
public:
    long long num1, num2;
    Calculator(long long a, long long b) : num1(a), num2(b) {}
    long long add() const { return num1 + num2; }
    long long subtract() const { return num1 - num2; }
    long long multiply() const { return num1 * num2; }
    double divide() const { return static_cast<double>(num1) / static_cast<double>(num2); }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0;
    while(T--) {
        long long a,b; cin>>a>>b;
        Calculator calc(a,b);
        cout<<calc.add()<<'\n';
        cout<<calc.subtract()<<'\n';
        cout<<calc.multiply()<<'\n';
        cout<<calc.divide()<<'\n';
    }
    return 0;
}

