import java.io.*;
import java.util.*;

public class Main {
    static class Calculator {
        long num1, num2;
        Calculator(long a, long b) { this.num1 = a; this.num2 = b; }
        long add() { return num1 + num2; }
        long subtract() { return num1 - num2; }
        long multiply() { return num1 * num2; }
        double divide() { return (double) num1 / (double) num2; }
    }
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st = new StringTokenizer(br.readLine());
        int T = Integer.parseInt(st.nextToken());
        StringBuilder sb = new StringBuilder();
        for (int i = 0; i < T; i++) {
            st = new StringTokenizer(br.readLine());
            long a = Long.parseLong(st.nextToken());
            long b = Long.parseLong(st.nextToken());
            Calculator calc = new Calculator(a, b);
            sb.append(calc.add()).append('\n');
            sb.append(calc.subtract()).append('\n');
            sb.append(calc.multiply()).append('\n');
            sb.append(calc.divide()).append('\n');
        }
        System.out.print(sb.toString());
    }
}

