#!/usr/bin/env python3
import sys

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        a = int(next(it))
        b = int(next(it))
        class Calculator:
            def __init__(self, x, y):
                self.x = x
                self.y = y
            def add(self):
                return self.x + self.y
            def subtract(self):
                return self.x - self.y
            def multiply(self):
                return self.x * self.y
            def divide(self):
                return self.x / self.y
        calc = Calculator(a, b)
        out_lines.append(str(calc.add()))
        out_lines.append(str(calc.subtract()))
        out_lines.append(str(calc.multiply()))
        out_lines.append(str(calc.divide()))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    main()

